const body = $input.item.json.body || $input.item.json;
const binary = $input.item.binary || {};

const patient_code = (body.patient_code || '').trim();
const interview_date = (body.interview_date || '').trim();
const interviewer = (body.interviewer || '').trim();

if (!patient_code || !/^PT-\d{4}-\d{3}$/.test(patient_code)) {
  throw new Error(`유효하지 않은 환자 코드: "${patient_code}". 형식: PT-YYYY-NNN`);
}
if (!interview_date || !/^\d{4}-\d{2}-\d{2}$/.test(interview_date)) {
  throw new Error(`유효하지 않은 면담 날짜: "${interview_date}". 형식: YYYY-MM-DD`);
}
if (!interviewer) {
  throw new Error('면담자(interviewer) 정보가 없습니다.');
}
if (!binary.audio) {
  throw new Error('오디오 파일이 없습니다. Form-data 필드명 "audio"로 전송하세요.');
}

const fileSizeBytes = binary.audio.fileSize || 0;
const fileSizeMB = fileSizeBytes / (1024 * 1024);
const needs_chunking = fileSizeMB > 24;

const dateStr = interview_date.replace(/-/g, '');
const origExt = ((binary.audio.fileName || 'recording.m4a').split('.').pop() || 'm4a').toLowerCase();
const audioFileName = `audio_${dateStr}.${origExt}`;
const sttFileName = `stt_${dateStr}.json`;

return [{
  json: {
    patient_code,
    interview_date,
    interviewer,
    interview_type: body.interview_type || 'followup',
    fileSizeMB: Math.round(fileSizeMB * 100) / 100,
    needs_chunking,
    audioFileName,
    sttFileName,
    dateStr
  },
  binary
}];

const w = $input.item.json;
const v = $('요청 검증').first().json;

// gpt-4o-transcribe: response_format='json' → { text: '...' } only
// verbose_json (segments, duration, language) 미지원
const sttResult = {
  data_type: 'stt_transcript',
  patient_code: v.patient_code,
  interview_date: v.interview_date,
  interviewer: v.interviewer,
  interview_type: v.interview_type || 'followup',
  created_at: $now.toISO(),
  audio_file: v.audioFileName,
  stt_engine: 'gpt-4o-transcribe',
  language: 'ko',
  duration_seconds: null,
  full_text: w.text || '',
  segments: [],
  word_count: (w.text || '').split(/\s+/).filter(t => t.length > 0).length
};

return [{
  json: {
    patient_code: v.patient_code,
    interview_date: v.interview_date,
    interviewer: v.interviewer,
    audioFileName: v.audioFileName,
    sttFileName: v.sttFileName,
    dateStr: v.dateStr,
    sttResult
  }
}];

const s = $('STT 결과 정리').first().json;
let folderId;
try {
  folderId = $('환자 폴더 생성').first().json.id;
} catch(e) {
  folderId = $('환자 폴더 존재 확인').first().json.id;
}
return [{ json: { ...s, folderId } }];

const p = $('폴더 ID 확정').first().json;
let audioFolderId;
try {
  audioFolderId = $('audio 폴더 생성').first().json.id;
} catch(e) {
  audioFolderId = $('audio 서브폴더 조회').first().json.id;
}
const audioBinary = $('요청 검증').first().binary;
return [{ json: { ...p, audioFolderId }, binary: audioBinary }];

const d = $('audio ID 확정').first().json;
const buf = Buffer.from(JSON.stringify(d.sttResult, null, 2), 'utf-8');
return [{
  json: {
    audioFolderId: d.audioFolderId,
    sttFileName: d.sttFileName,
    patient_code: d.patient_code,
    interview_date: d.interview_date,
    interviewer: d.interviewer,
    audioFileName: d.audioFileName,
    wordCount: d.sttResult.word_count,
    duration: d.sttResult.duration_seconds
  },
  binary: {
    data: {
      data: buf.toString('base64'),
      mimeType: 'application/json',
      fileName: d.sttFileName
    }
  }
}];
